arguments.argument:
if global.gamePaused=false
{
  if xDraw<16 {xDraw+=0.2}
  
  if myProg=0
  {
    if oGame.time mod 2=0
    {
      if image_alpha=1 {image_alpha=0.5}
      else {image_alpha=1}
    }
  }
  else if myProg=1
  {
    image_alpha=1
    myProg=2
  }
  else if myProg=2
  {
    image_alpha-=0.05
    if image_alpha<=0 {instance_destroy()}
  }
}
